int n;

struct dat{int h,i;};



int calc(int A[]){

  stack <dat> S;

  int res = 0;

  for(int i=0;i<=n;i++){

    int h = A[i];

    if(S.empty() || S.top().h < h) S.push((dat){h,i});

    else if(S.top().h > h){

      int ni = i;

      while(!S.empty() && S.top().h > h){

        dat t = S.top(); S.pop();

        ni = t.i;

        int area = (i - t.i) * t.h;

        res = max(res,area);

      }

      res = max(res,(i-ni)*h);

      S.push((dat){h,ni});

    }

  }

  return res;

}



